DECLARE @fact char(2);
DECLARE @as_find varchar(30);
DECLARE @setl char(2);
SET @fact = ?;
SET @as_find = ?;
SET @setl = ?;
SET @as_find = '%'+@as_find+'%';

DECLARE @ColumnList NVARCHAR(MAX);
DECLARE @SQL NVARCHAR(MAX);

SET @ColumnList = STUFF((
    SELECT ', obot_' + code_code + ' AS [' + code_name + ']'
    FROM bacode WITH (NOLOCK)
    WHERE code_fact = @fact 
      AND code_gubn = 'OBOT_1'
    ORDER BY code_code
    FOR XML PATH(''), TYPE).value('.', 'NVARCHAR(MAX)'), 1, 2, '');

SET @SQL = N'
SELECT ' + @ColumnList + N'
FROM baobot WITH (NOLOCK)
WHERE obot_fact = @fact 
  and obot_setl = @setl 
  and( (obot_tex1 like @as_find ) or (obot_tex2 like @as_find ) or (obot_tex3 like @as_find) or (obot_tex4 like @as_find) )
  AND obot_gubn = ''1''';

EXEC sp_executesql @SQL, 
                   N'@fact CHAR(2), @setl CHAR(2), @as_find VARCHAR(30)', 
                   @fact = @fact, 
                   @setl = @setl, 
                   @as_find = @as_find;
